// Auto-generated OECS logo as base64 data URI
// Do not edit manually - regenerate from frontend/public/OECS.png

export const OECS_LOGO_BASE64 = 'data:image/png;base64,';

export function getLogoFooterHTML(extraText: string = ''): string {
  const date = new Date().toLocaleDateString();
  const time = new Date().toLocaleTimeString();
  return `
    <!-- Footer -->
    <div style="
      margin-top: 3rem;
      padding-top: 1rem;
      border-top: 1px solid #e5e7eb;
      overflow: hidden;
    ">
      <img src="${OECS_LOGO_BASE64}" style="float: right; height: 28px; opacity: 0.85;" alt="OECS" />
      <div style="color: #9ca3af; font-size: 0.75rem; line-height: 28px;">
        Generated on ${date} at ${time}${extraText}
      </div>
    </div>
  `;
}
